mapper.select:
SELECT m.*, u.username, u.avatar as userAvatar
FROM moments m
JOIN user u ON m.user_id = u.id
WHERE 



        m.id = #{momentId}
        AND (
            m.user_id = #{currentUserId} -- Own moments
            OR m.visibility = 'PUBLIC'
            OR (m.visibility = 'FRIENDS' AND EXISTS (
                SELECT 1 FROM friend WHERE user_id = m.user_id AND friend_id = #{currentUserId}
            ))
            OR (m.visibility = 'PARTIAL' AND EXISTS (SELECT 1 FROM moment_visibility mv WHERE mv.moment_id = m.id AND mv.user_id = #{currentUserId}))
            OR (m.visibility = 'EXCLUDE' AND NOT EXISTS (SELECT 1 FROM moment_visibility mv WHERE mv.moment_id = m.id AND mv.user_id = #{currentUserId}))
        )



        m.user_id = #{targetUserId}
        AND (
            m.user_id = #{currentUserId} -- Own moments
            OR (
                m.visibility = 'PUBLIC'
                OR (m.visibility = 'FRIENDS' AND EXISTS (
                    SELECT 1 FROM friend WHERE user_id = #{targetUserId} AND friend_id = #{currentUserId}
                ))
                OR (m.visibility = 'PARTIAL' AND EXISTS (SELECT 1 FROM moment_visibility mv WHERE mv.moment_id = m.id AND mv.user_id = #{currentUserId}))
                OR (m.visibility = 'EXCLUDE' AND NOT EXISTS (SELECT 1 FROM moment_visibility mv WHERE mv.moment_id = m.id AND mv.user_id = #{currentUserId}))
            )
        )



        (
            m.user_id = #{currentUserId} -- Own moments
            OR (
                m.user_id IN 

                    #{fid}

                AND (
                    m.visibility = 'PUBLIC'
                    OR m.visibility = 'FRIENDS'
                    OR (m.visibility = 'PARTIAL' AND EXISTS (SELECT 1 FROM moment_visibility mv WHERE mv.moment_id = m.id AND mv.user_id = #{currentUserId}))
                    OR (m.visibility = 'EXCLUDE' AND NOT EXISTS (SELECT 1 FROM moment_visibility mv WHERE mv.moment_id = m.id AND mv.user_id = #{currentUserId}))
                )
            )
        )


ORDER BY m.created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT ml.*, u.username FROM moment_likes ml JOIN user u ON ml.user_id = u.id WHERE ml.moment_id IN
#{mid}
ORDER BY ml.created_at ASC

SELECT mc.*, u.username, ru.username as replyToUsername FROM moment_comments mc JOIN user u ON mc.user_id = u.id LEFT JOIN user ru ON mc.reply_to_user_id = ru.id WHERE mc.moment_id IN
#{mid}
ORDER BY mc.created_at ASC

SELECT COUNT(*)
FROM moments m
WHERE m.created_at > #{lastReadAt}
  AND (
      m.user_id = #{userId} 
      OR

          m.user_id IN

              #{friendId}



          1 = 0

  )
  AND m.user_id != #{userId} 
  AND (
      m.visibility = 'PUBLIC'
      OR m.visibility = 'FRIENDS'
      OR (m.visibility = 'PARTIAL' AND EXISTS (SELECT 1 FROM moment_visibility mv WHERE mv.moment_id = m.id AND mv.user_id = #{userId}))
      OR (m.visibility = 'EXCLUDE' AND NOT EXISTS (SELECT 1 FROM moment_visibility mv WHERE mv.moment_id = m.id AND mv.user_id = #{userId}))
  )
